class Solution:
    def mostWordsFound(self, sentences):
        best = 0
        for s in sentences:
            words = s.split(' ')
            if len(words) > best:
                best = len(words)
        return best

solutions.python:
class Solution:
    def mostWordsFound(self, sentences):
        return max(s.count(' ') + 1 for s in sentences)

